```cpp
#include <iostream>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <cstdio>
#include <cerrno>

int main() {
    int pipefd[2];
    pid_t pid;

    // Create a pipe
    if (pipe(pipefd) == -1) {
        perror("Pipe failed");
        return 1;
    }

    // Fork a new process
    pid = fork();

    if (pid < 0) {
        perror("Fork failed");
        return 1;
    } else if (pid == 0) {
        // Child process
        // Close all unnecessary file descriptors
        close(pipefd[1]);

        // Duplicate the pipe file descriptor to stdin and stdout
        dup2(pipefd[0], STDIN_FILENO);
        dup2(pipefd[0], STDOUT_FILENO);

        // Close the pipe file descriptor
        close(pipefd[0]);

        // Execute a new program, e.g., /bin/ls
        execlp("/bin/ls", "ls", NULL);

        // If execlp fails
        perror("execlp failed");
        return 1;
    } else {
        // Parent process
        // Close the read end of the pipe
        close(pipefd[0]);

        // Use the write end of the pipe for communication
        std::cout << "Parent process is ready." << std::endl;

        // Wait for the child process to finish
        wait(NULL);

        // Close the write end of the pipe
        close(pipefd[1]);
    }

    return 0;
}
```

This code snippet demonstrates how to create a pipe, fork a new process, and connect the pipe to the child process's standard input and output. The parent process waits for the child process to finish. Make sure to link against the necessary libraries if needed.

